local function safe_load_code(code)
    if not code or type(code) ~= "string" then
        return nil, "Invalid code"
    end
    
    -- Basic validation to prevent code injection
    if string.find(code, "package") or 
       string.find(code, "require") or 
       string.find(code, "io.") or 
       string.find(code, "os.") or 
       string.find(code, "load") or
       string.find(code, "dofile") or
       string.find(code, "loadfile") then
        return nil, "Forbidden functions detected"
    end
    
    -- Check for dangerous patterns
    local dangerous_patterns = {
        "collectgarbage", "debug", "io", "os", "package", "require", 
        "rawset", "rawget", "setmetatable", "getmetatable", "pcall"
    }
    
    for _, pattern in ipairs(dangerous_patterns) do
        if string.find(code, pattern) then
            return nil, "Forbidden pattern detected: " .. pattern
        end
    end
    
    -- Check for function definitions that might be dangerous
    if string.find(code, "function.*%(") then
        local func_count = 0
        for _ in string.gmatch(code, "function") do
            func_count = func_count + 1
        end
        if func_count > 10 then
            return nil, "Too many function definitions"
        end
    end
    
    local func, err = loadstring(code)
    if not func then
        return nil, "Load failed: " .. tostring(err)
    end
    
    return func
end

local function execute_plugin_from_redis(redis_host, redis_port, key)
    local red = redis:new()
    red:set_timeout(1000)
    
    local ok, err = red:connect(redis_host, redis_port)
    if not ok then
        return nil, "Failed to connect to Redis: " .. tostring(err)
    end
    
    local code, err = red:get(key)
    if not code then
        return nil, "Failed to get code from Redis: " .. tostring(err)
    end
    
    if code == ngx.null then
        return nil, "No code found in Redis"
    end
    
    local func, err = safe_load_code(code)
    if not func then
        return nil, "Failed to load code: " .. tostring(err)
    end
    
    return func
end

local function execute_plugin_from_header(header_name)
    local code = ngx.var[header_name]
